mapper.select:
SELECT o.id, o.order_no, o.check_in_date, o.check_out_date, o.total_amount, o.status, o.create_time, h.name_cn AS hotel_name, (SELECT url FROM t_hotel_image hi WHERE hi.hotel_id = h.id AND hi.type = 1 ORDER BY hi.sort_order LIMIT 1) AS hotel_image, CASE o.status WHEN 0 THEN '待支付' WHEN 1 THEN '已支付' WHEN 2 THEN '已取消' WHEN 3 THEN '已入住' WHEN 4 THEN '退房申请中' WHEN 5 THEN '已退房' WHEN 6 THEN '已完成' END AS status_text FROM t_order o INNER JOIN t_hotel h ON o.hotel_id = h.id WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC
